func unwrapPage(in any) (page.Page, error) {
	switch v := in.(type) {
	case *pageState:
		return v, nil
	case pageWrapper:
		return v.page(), nil
	case types.Unwrapper:
		return unwrapPage(v.Unwrapv())
	case page.Page:
		return v, nil
	case nil:
		return nil, nil
	default:
		return nil, fmt.Errorf("unwrapPage: %T not supported", in)
	}
}
